import{_ as t,c as n,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Mehrsprachige Unterstützung: Automatische Sprachumschaltung | opencode-mystatus","description":"Erfahren Sie die Spracherkennungsprinzipien von opencode-mystatus (Intl-API + Umgebungsvariablen-Fallback) und wie Sie die Ausgabesprache wechseln.","frontmatter":{"title":"Mehrsprachige Unterstützung: Automatische Sprachumschaltung | opencode-mystatus","sidebarTitle":"Mehrsprachige","subtitle":"Mehrsprachige Unterstützung: Automatische Umschaltung zwischen Chinesisch und Englisch","description":"Erfahren Sie die Spracherkennungsprinzipien von opencode-mystatus (Intl-API + Umgebungsvariablen-Fallback) und wie Sie die Ausgabesprache wechseln.","tags":["i18n","Internationalisierung","Spracherkennung","Mehrsprachigkeit"],"prerequisite":["start-quick-start"],"order":3},"headers":[],"relativePath":"de/vbgate/opencode-mystatus/advanced/i18n-setup/index.md","filePath":"de/vbgate/opencode-mystatus/advanced/i18n-setup/index.md"}'),i={name:"de/vbgate/opencode-mystatus/advanced/i18n-setup/index.md"};function r(h,e,l,c,d,o){return s(),n("div",null,[...e[0]||(e[0]=[a(`<h1 id="mehrsprachige-unterstutzung-automatische-umschaltung-zwischen-chinesisch-und-englisch" tabindex="-1">Mehrsprachige Unterstützung: Automatische Umschaltung zwischen Chinesisch und Englisch <a class="header-anchor" href="#mehrsprachige-unterstutzung-automatische-umschaltung-zwischen-chinesisch-und-englisch" aria-label="Permalink to &quot;Mehrsprachige Unterstützung: Automatische Umschaltung zwischen Chinesisch und Englisch&quot;">​</a></h1><h2 id="was-sie-nach-diesem-tutorial-konnen" tabindex="-1">Was Sie nach diesem Tutorial können <a class="header-anchor" href="#was-sie-nach-diesem-tutorial-konnen" aria-label="Permalink to &quot;Was Sie nach diesem Tutorial können&quot;">​</a></h2><ul><li>Erfahren, wie mystatus automatisch die Systemsprache erkennt</li><li>Wissen, wie Sie durch Wechseln der Systemsprache die Ausgabesprache ändern</li><li>Verstehen der Priorität und des Fallback-Mechanismus der Spracherkennung</li><li>Meistern der Funktionsweise von Intl-API und Umgebungsvariablen</li></ul><h2 id="grundlegende-idee" tabindex="-1">Grundlegende Idee <a class="header-anchor" href="#grundlegende-idee" aria-label="Permalink to &quot;Grundlegende Idee&quot;">​</a></h2><p><strong>Mehrsprachige Unterstützung</strong> wählt automatisch Chinesisch oder Englisch basierend auf der Systemspracheumgebung aus, ohne manuelle Konfiguration. Die Erkennungspriorität ist: Intl-API → Umgebungsvariablen → Standard Englisch.</p><p><strong>Erkennungspriorität</strong> (von hoch nach niedrig):</p><ol><li><strong>Intl-API</strong> (empfohlen) → <code>Intl.DateTimeFormat().resolvedOptions().locale</code></li><li><strong>Umgebungsvariablen</strong> (Fallback) → <code>LANG</code>, <code>LC_ALL</code>, <code>LANGUAGE</code></li><li><strong>Standard Englisch</strong> (Fallback) → <code>&quot;en&quot;</code></li></ol><p><strong>Unterstützte Sprachen</strong>:</p><table tabindex="0"><thead><tr><th>Sprache</th><th>Code</th><th>Erkennungsbedingung</th></tr></thead><tbody><tr><td>Chinesisch</td><td><code>zh</code></td><td>locale beginnt mit <code>zh</code> (z. B. <code>zh-CN</code>, <code>zh-TW</code>)</td></tr><tr><td>Englisch</td><td><code>en</code></td><td>Andere Fälle</td></tr></tbody></table><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-aktuelle-systemsprache-anzeigen" tabindex="-1">Schritt 1: Aktuelle Systemsprache anzeigen <a class="header-anchor" href="#schritt-1-aktuelle-systemsprache-anzeigen" aria-label="Permalink to &quot;Schritt 1: Aktuelle Systemsprache anzeigen&quot;">​</a></h3><p>Bestätigen Sie zunächst Ihre Systemspracheinstellungen:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $LANG</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Chinesisches System: <code>zh_CN.UTF-8</code>, <code>zh_TW.UTF-8</code> oder ähnlich</li><li>Englisches System: <code>en_US.UTF-8</code>, <code>en_GB.UTF-8</code> oder ähnlich</li></ul><h3 id="schritt-2-spracherkennung-testen" tabindex="-1">Schritt 2: Spracherkennung testen <a class="header-anchor" href="#schritt-2-spracherkennung-testen" aria-label="Permalink to &quot;Schritt 2: Spracherkennung testen&quot;">​</a></h3><p>Führen Sie <code>/mystatus</code> aus und beobachten Sie die Ausgabesprache:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mystatus</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>:</p><ul><li>Wenn die Systemsprache Chinesisch ist → Ausgabe auf Chinesisch (z. B. <code>3小时限额</code>, <code>重置: 2小时30分钟后</code>)</li><li>Wenn die Systemsprache Englisch ist → Ausgabe auf Englisch (z. B. <code>3-hour limit</code>, <code>Resets in: 2h 30m</code>)</li></ul><h3 id="schritt-3-temporarer-systemsprachwechsel-zum-testen" tabindex="-1">Schritt 3: Temporärer Systemsprachwechsel (zum Testen) <a class="header-anchor" href="#schritt-3-temporarer-systemsprachwechsel-zum-testen" aria-label="Permalink to &quot;Schritt 3: Temporärer Systemsprachwechsel (zum Testen)&quot;">​</a></h3><p>Wenn Sie die Ausgabe in verschiedenen Sprachen testen möchten, können Sie die Umgebungsvariablen vorübergehend ändern:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Temporär auf Englisch umschalten</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">LANG</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">en_US.UTF-8</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> /mystatus</span></span></code></pre></div><p><strong>Was Sie sehen sollten</strong>: Auch wenn Ihr System chinesisch ist, wird die Ausgabe englisch.</p><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Dies ist nur ein temporärer Test, die Systemsprache wird nicht dauerhaft geändert. Nach Schließen des Terminals wird die ursprüngliche Einstellung wiederhergestellt.</p></div><h2 id="haufige-fehler" tabindex="-1">Häufige Fehler <a class="header-anchor" href="#haufige-fehler" aria-label="Permalink to &quot;Häufige Fehler&quot;">​</a></h2><h3 id="haufige-probleme" tabindex="-1">Häufige Probleme <a class="header-anchor" href="#haufige-probleme" aria-label="Permalink to &quot;Häufige Probleme&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Problem</th><th>Ursache</th><th>Lösung</th></tr></thead><tbody><tr><td>Ausgabesprache entspricht nicht den Erwartungen</td><td>Falsche Systemspracheinstellung</td><td>Überprüfen Sie die Umgebungsvariable <code>LANG</code> oder die Systemspracheinstellung</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Chinesisches System zeigt Englisch an</td><td>Umgebungsvariable <code>LANG</code> nicht auf <code>zh_*</code> gesetzt</td><td>Stellen Sie den korrekten <code>LANG</code>-Wert ein (z. B. <code>zh_CN.UTF-8</code>)</td></tr></tbody></table><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><ul><li><strong>Automatische Erkennung</strong>: mystatus erkennt automatisch die Systemsprache, ohne manuelle Konfiguration</li><li><strong>Erkennungspriorität</strong>: Intl-API → Umgebungsvariablen → Standard Englisch</li><li><strong>Unterstützte Sprachen</strong>: Chinesisch (<code>zh</code>) und Englisch (<code>en</code>)</li><li><strong>Sprachwechsel</strong>: Ändern der Systemspracheinstellung, OpenCode neu starten</li></ul><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Spracherkennungsfunktion</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/i18n.ts#L24-L40" target="_blank" rel="noreferrer"><code>plugin/lib/i18n.ts</code></a></td><td>24-40</td></tr></tbody></table><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>detectLanguage()</code>: Erkennt die Systemsprache des Benutzers, priorisiert Intl-API, fällt auf Umgebungsvariablen zurück, Standard Englisch</li></ul></details>`,33)])])}const p=t(i,[["render",r]]);export{g as __pageData,p as default};
